//선사 pop 
scwin.udc_comCode_shp_onclickEvent = function (e) {
  udc_comCode_shp.cfCommonPopUp(scwin.udc_comCode_shp_callBackFunc, ed_shpCo.getValue(), ed_shpNm.getValue(), "T", null, null, null, null, "SHP", null, null, null, null, null, null, "선사,선사코드,선사명", null);
};

//선사 팝업 callback
scwin.udc_comCode_shp_callBackFunc = function (ret) {
  if (ret == null || ret == "N/A") {
    ed_shpCo.setValue("");
    ed_shpNm.setValue("");
    scwin.hid_chkshpCd = "";
  } else if (ret != null) {
    ed_shpCo.setValue(ret[0]);
    ed_shpNm.setValue(ret[1]);
    scwin.hid_chkshpCd = ret[0];
  }
  scwin.f_setLine();
};
scwin.udc_comCode_shp_onblurCodeEvent = function (e) {
  if (ed_shpCo.getValue() === "") {
    ed_shpNm.setValue("");
    scwin.f_setLine();
  } else {
    udc_comCode_shp.cfCommonPopUp(scwin.udc_comCode_shp_callBackFunc, ed_shpCo.getValue(), ed_shpNm.getValue(), "T", null, null, null, null, "SHP", null, null, null, null, null, null, "선사,선사코드,선사명", null);
  }
};
scwin.udc_comCode_shp_onviewchangeNameEvent = function (info) {
  if (ed_shpNm.getValue() === "") {
    ed_shpCo.setValue("");
    scwin.f_setLine();
  } else {
    ed_shpCo.setValue("");
    udc_comCode_shp.cfCommonPopUp(scwin.udc_comCode_shp_callBackFunc, ed_shpCo.getValue(), ed_shpNm.getValue(), "T", null, null, null, null, "SHP", null, null, null, null, null, null, "선사,선사코드,선사명", null);
  }
};

