//scwin.excelDw
scwin.excelDw = async function () {
  let options = {
    fileName: "Daily Cntr Movement.xlsx",
    sheetName: "Daily Cntr Movement"
  };
  let grdObj = gr_Grid1;
  let infoArr = {};
  if (ds_Grid1.getTotalRow() == 0) {
    //전체total count
    $c.win.alert($p, MSG_CM_WRN_002);
  } else {
    if (await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?")) {
      $c.data.downloadGridViewExcel($p, grdObj, options, infoArr);
    }
  }
};

//MOL발행
scwin.button_print_onclick = async function (e) {
  let options = {
    fileName: "Daily Cntr Movement.xlsx",
    sheetName: "Daily Cntr Movement"
  };
  let features = "copyHeader=yes,rowFrom=1,rowCnt=" + ds_Grid1.getRowCount();
  $c.gus.cfCopyDataSet($p, ds_Grid1, ds_Grid2, features);
  let grdObj = gr_Grid2;
  let infoArr = {};
  if (ds_Grid2.getTotalRow() == 0) {
    //전체total count
    $c.win.alert($p, MSG_CM_WRN_002);
  } else {
    if (await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?")) {
      $c.data.downloadGridViewExcel($p, grdObj, options, infoArr);
    }
  }
};
